-- First, remove any items with NULL monitor_id to avoid PK violation\nDELETE FROM "items" WHERE "monitor_id" IS NULL;\n\n-- Drop old PK\nALTER TABLE "items" DROP CONSTRAINT "items_pkey";\n\n-- Make monitor_id NOT NULL\nALTER TABLE "items" ALTER COLUMN "monitor_id" SET NOT NULL;\n\n-- Add new composite PK\nALTER TABLE "items" ADD CONSTRAINT "items_pkey" PRIMARY KEY ("id", "monitor_id");
